mapper.select:
SELECT id, session_id, user_id, tenant_id, title, status, created_by, created_at, updated_by, updated_at, deleted
FROM cs_session
WHERE deleted = FALSE
  AND user_id = #{userId}
  AND tenant_id = #{tenantId}
ORDER BY updated_at DESC, id DESC

mapper.update:
UPDATE cs_session
SET
    title = COALESCE(#{title}, title),
    status = COALESCE(#{status}, status),
    updated_at = CURRENT_TIMESTAMP
WHERE deleted = FALSE
  AND session_id = #{sessionId}
  AND user_id = #{userId}
  AND tenant_id = #{tenantId}

UPDATE cs_session
SET deleted = TRUE,
    updated_at = CURRENT_TIMESTAMP
WHERE deleted = FALSE
  AND session_id = #{sessionId}
  AND user_id = #{userId}
  AND tenant_id = #{tenantId}
